sql:
SELECT programs.program_name, institutes.institute_name
FROM programs
INNER JOIN institutes ON programs.institute_id = institutes.institute_id;

SELECT feedback, rating
FROM program_feedback
WHERE program_id = 0;

external_knowledge:
- "seeds have sprouted" refers to 'attended';
- "garden plots" refers to 'programs';
- "can only accommodate a limited number of flowers, less than a hundred" refers to programs with 'capacity < 100'.

sql:
SELECT user_name, email 
FROM users 
WHERE user_id = (SELECT updated_by FROM program_status WHERE program_id = 1002);

SELECT program_id, COUNT(*) as num_attendees
FROM attendees
GROUP BY program_id;

SELECT p1.program_name, p2.program_name
FROM programs p1
JOIN programs p2 ON p1.duration = p2.duration AND p1.program_id <> p2.program_id;

SELECT AVG(rating) 
FROM program_feedback 
WHERE program_id = 1;

SELECT programs.program_name, program_feedback.feedback
FROM programs
JOIN program_feedback ON programs.program_id = program_feedback.program_id;

SELECT name 
FROM attendees 
WHERE program_id = 1;

SELECT venue_name
FROM venues
WHERE capacity > 50 AND venue_id IN (
    SELECT location_id
    FROM programs
);

SELECT a.name AS user_name
FROM attendees a
WHERE a.name = 'John Doe';
